package com.tnsif.Day2;

public class DecisionMakingWithOperators {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int x=6,y=5;
		int a=12,b=13;
		if(x>=y) {
			System.out.println("true");
		} else {
			System.out.println("false");
		}
		if((a<b)||(a==b)) {
			System.out.println("true");
		}else {
			System.out.println("false");
		}

	}

}
